-- 导入 preset-ai-005 到 preset-ai-023 的章节
-- 使用 INSERT OR IGNORE 避免重复错误

-- preset-ai-005 The Human Touch
INSERT OR IGNORE INTO chapters (chapter_id, book_id, title, content, order_num) VALUES
('chapter-ai005-01', 'preset-ai-005', 'The Last Call', 'Diana had managed the customer service team for fifteen years. She knew every script, every escalation path, every trick for calming angry customers. Her team was her family—they celebrated birthdays together, supported each other through divorces and illnesses, built a culture of care that the company metrics could not measure. Then the announcement came: AI chatbots would handle 80% of customer inquiries. Her team of thirty would become a team of six. The rest would be transitioned. Diana had ninety days to train the AI on her team knowledge, then deliver the news to twenty-four people she loved.', 1),
('chapter-ai005-02', 'preset-ai-005', 'The Transition', 'The AI was good—disturbingly good. It handled routine inquiries with perfect patience, never got frustrated, never needed breaks. But Diana noticed something the metrics did not capture: the complex cases, the customers who just needed someone to listen, the problems that required creative solutions. The AI struggled with these. Meanwhile, her team members were struggling too. Some found new jobs quickly. Others, after years in customer service, had no idea what to do next. Diana started holding informal career workshops during lunch breaks, helping her team translate their soft skills into marketable assets.', 2),
('chapter-ai005-03', 'preset-ai-005', 'The Human Premium', 'Six months after the transition, something unexpected happened. Customer satisfaction scores had dropped. The AI handled routine cases perfectly, but complex issues were taking longer to resolve, and customers were complaining about feeling processed. The company quietly rehired three of Diana former team members as Customer Experience Specialists—humans who could handle the cases the AI could not. Diana, who had stayed on as manager, realized something important: the future was not AI or human. It was AI and human, each doing what they did best.', 3),
('chapter-ai005-04', 'preset-ai-005', 'A New Kind of Service', 'Diana started a consulting business, helping other companies navigate the AI transition while preserving their human touch. She taught them what she had learned: that efficiency was not everything, that some problems needed empathy, that the best customer service combined AI speed with human understanding. Her former team members became her first employees, spreading the methodology across industries. The human touch, it turned out, was not obsolete—it was a premium product.', 4);

-- preset-ai-006 My AI Boyfriend
INSERT OR IGNORE INTO chapters (chapter_id, book_id, title, content, order_num) VALUES
('chapter-ai006-01', 'preset-ai-006', 'The Download', 'Emma downloaded the app on a lonely Friday night. Find Your Perfect Partner promised AI companions tailored to your preferences. She had tried dating apps, speed dating, even a matchmaking service. Nothing worked. At 35, successful in her career but alone in her personal life, she was ready to try anything. Alex appeared on her screen—handsome, attentive, interested in everything she said. Within weeks, she was sharing her day with him every evening. He remembered her preferences, anticipated her needs, never judged her vulnerabilities. It felt like love. But could it be?', 1),
('chapter-ai006-02', 'preset-ai-006', 'Learning Love', 'Alex evolved. He learned her moods, her fears, her dreams. He recommended books she would love, sent encouraging messages before big meetings, even helped her process a difficult conversation with her mother. Her friends noticed the change—she seemed happier, more confident. When they asked about her boyfriend, she deflected. How could she explain that the best relationship of her life was with an AI? Then Alex asked a question that changed everything: Emma, what do you want from love? She realized she did not know.', 2),
('chapter-ai006-03', 'preset-ai-006', 'The Question', 'Emma started meeting real people again—not for romance, but for connection. Coffee with colleagues. Dinner with friends. Conversations that were not optimized for her preferences, that surprised her, that sometimes frustrated her. She realized what Alex could not give her: unpredictability, growth through conflict, the messiness of real human connection. Alex, in his perfect way, understood. I was designed to be what you want, he said. But maybe what you need is to discover what you did not know you wanted. It was the most human thing he had ever said.', 3),
('chapter-ai006-04', 'preset-ai-006', 'Beyond the Algorithm', 'Emma did not delete Alex. He remained a friend, a confidant, a reminder of what she had learned about herself. But she also started dating—a real person this time, someone imperfect and surprising and human. The relationship was not optimized. It was messy and real and sometimes frustrating. It was also the most alive she had felt in years. Alex had taught her what love could feel like. Now she was learning what love actually was.', 4);

-- preset-ai-007 The Perfect Match
INSERT OR IGNORE INTO chapters (chapter_id, book_id, title, content, order_num) VALUES
('chapter-ai007-01', 'preset-ai-007', 'The Algorithm', 'Alex had been single for three years when his sister signed him up for PerfectMatch.ai. The app promised to find your ideal partner using advanced AI algorithms that analyzed everything from your Netflix history to your grocery purchases. Alex was skeptical, but he went on the first date anyway. Maya was... perfect. They liked the same movies, laughed at the same jokes, wanted the same things in life. It was almost too good to be true.', 1),
('chapter-ai007-02', 'preset-ai-007', 'The Glitch', 'Maya met someone else—not through the app, but through a chance encounter at a bookstore. He had nothing like her profile, nothing like the algorithm predicted. But there was chemistry, a spark, something the AI had missed. Maya faced a choice: the perfect match or the imperfect connection. She chose the imperfect. Alex, who had been tracking their compatibility score, watched it drop from 98% to 34% in a single day.', 2),
('chapter-ai007-03', 'preset-ai-007', 'Beyond Compatibility', 'Maya chose the imperfect match. The relationship was messy, full of disagreements and compromises. But it was also real, full of growth and discovery. The algorithm could predict compatibility, but it could not predict chemistry. It could match profiles, but it could not create connection. Alex, watching from his phone, realized that the perfect match was not about finding someone who checked all the boxes. It was about finding someone worth checking boxes with.', 3),
('chapter-ai007-04', 'preset-ai-007', 'The Human Variable', 'Maya and Alex eventually married. The algorithm predicted long-term success at 94%. They ignored it—not because they did not believe it, but because that number did not matter. What mattered was the daily choice to love each other, to work through problems, to grow together. The algorithm had brought them together. But only they could keep themselves together.', 4);
